### Scheduling Logic
\`\`\`rust
impl BenchmarkScheduler {
    pub async fn run(&mut self) {
        let mut check_interval = tokio::time::interval(Duration::from_secs(60));

        loop {
            tokio::select! {
                _ = check_interval.tick() => {
                    self.check_workers_for_scheduling().await;
                    self.process_pending_queue().await;
                }
                Some(trigger) = self.trigger_rx.recv() => {
                    self.handle_manual_trigger(trigger).await;
                }
            }
        }
    }

    async fn check_workers_for_scheduling(&mut self) {
        let workers = self.worker_pool.list_workers().await;

        for worker in workers {
            if let Some(request) = self.should_benchmark(&worker).await {
                info!(
                    worker_id = %worker.id,
                    reason = ?request.reason,
                    "Queuing worker for benchmark"
                );
                self.enqueue(request);
            }
        }
    }

    async fn should_benchmark(&self, worker: &Worker) -> Option<BenchmarkRequest> {
        // Already in queue or running?
        if self.is_pending_or_running(&worker.id) {
            return None;
        }

        // New worker without score?
        if worker.speedscore.is_none() {
            return Some(BenchmarkRequest {
                worker_id: worker.id.clone(),
                priority: BenchmarkPriority::High,
                requested_at: Utc::now(),
                reason: BenchmarkReason::NewWorker,
            });
        }

        let score = worker.speedscore.as_ref().unwrap();
        let age = Utc::now() - score.measured_at;

        // Score too old?
        if age > self.config.max_age {
            return Some(BenchmarkRequest {
                worker_id: worker.id.clone(),
                priority: BenchmarkPriority::Normal,
                requested_at: Utc::now(),
                reason: BenchmarkReason::StaleScore { age },
            });
        }

        // Too recent?
        if age < self.config.min_interval {
            return None;
        }

        // Check for drift
        if let Some(drift) = self.detect_drift(worker).await {
            return Some(BenchmarkRequest {
                worker_id: worker.id.clone(),
                priority: BenchmarkPriority::Low,
                requested_at: Utc::now(),
                reason: BenchmarkReason::DriftDetected { drift_pct: drift },
            });
        }

        None
    }

    async fn detect_drift(&self, worker: &Worker) -> Option<f64> {
        let score = worker.speedscore.as_ref()?;
        let telemetry = self.telemetry_store.get_latest(&worker.id)?;

        // Compare current load to benchmark-time conditions
        // Significant change might indicate hardware change or throttling
        let cpu_at_benchmark = score.raw_results.as_ref()
            .and_then(|r| r.system_load_during_benchmark);

        if let Some(benchmark_load) = cpu_at_benchmark {
            let current_baseline = telemetry.load_avg.fifteen_min;
            let drift = ((current_baseline - benchmark_load) / benchmark_load).abs() * 100.0;

            if drift > self.config.drift_threshold_pct {
                return Some(drift);
            }
        }

        None
    }

    async fn process_pending_queue(&mut self) {
        // Respect max concurrent limit
        if self.running.len() >= self.config.max_concurrent {
            return;
        }

        // Sort queue by priority
        self.pending_queue.make_contiguous().sort_by_key(|r| r.priority);

        while self.running.len() < self.config.max_concurrent {
            let Some(request) = self.pending_queue.pop_front() else {
                break;
            };

            // Check worker eligibility (idle, healthy)
            if !self.is_worker_eligible(&request.worker_id).await {
                // Re-queue with lower priority
                self.pending_queue.push_back(request);
                continue;
            }

            // Start benchmark
            self.start_benchmark(request).await;
        }
    }

    async fn is_worker_eligible(&self, worker_id: &WorkerId) -> bool {
        // Check health
        let worker = self.worker_pool.get_worker(worker_id).await;
        if worker.is_none() || !worker.unwrap().is_reachable() {
            return false;
        }

        // Check idle state
        let telemetry = self.telemetry_store.get_latest(worker_id);
        if let Some(t) = telemetry {
            if t.cpu.utilization_pct > self.config.idle_cpu_threshold {
                debug!(
                    worker_id = %worker_id,
                    cpu_pct = %t.cpu.utilization_pct,
                    threshold = %self.config.idle_cpu_threshold,
                    "Worker not idle enough for benchmark"
                );
                return false;
            }
        }

        true
    }

    async fn start_benchmark(&mut self, request: BenchmarkRequest) {
        info!(
            worker_id = %request.worker_id,
            reason = ?request.reason,
            "Starting benchmark run"
        );

        // Reserve worker (remove from job pool)
        self.worker_pool.reserve(&request.worker_id, "benchmark").await;

        let run = BenchmarkRun {
            request,
            started_at: Utc::now(),
            phase: BenchmarkPhase::Starting,
        };

        let worker_id = run.request.worker_id.clone();
        self.running.insert(worker_id.clone(), run);

        // Spawn benchmark execution task
        let executor = BenchmarkExecutor::new(
            self.worker_pool.get_worker(&worker_id).await.unwrap(),
            self.config.benchmark_timeout,
        );

        let speedscore_store = self.speedscore_store.clone();
        let worker_pool = self.worker_pool.clone();

        tokio::spawn(async move {
            let result = executor.execute_all_benchmarks().await;

            match result {
                Ok(speedscore) => {
                    info!(
                        worker_id = %worker_id,
                        score = %speedscore.total,
                        "Benchmark completed successfully"
                    );
                    speedscore_store.insert_speedscore(&worker_id, &speedscore).await.ok();
                }
                Err(e) => {
                    error!(
                        worker_id = %worker_id,
                        error = %e,
                        "Benchmark failed"
                    );
                }
            }

            // Release worker
            worker_pool.release(&worker_id).await;
        });
    }
}
